(918, 'Upper Hand', 'The user reacts to the target\'s movement and strikes with the heel of its palm, making the target flinch. This move fails if the target is not readying a priority move.', 65, 'physical', 'Fighting', 100, 0, 15),
(919, 'Malignant Chain', 'The user pours toxins into the target by wrapping it in a toxic chain. This may also leave the target badly poisoned.', 100, 'special', 'Poison', 100, 0, 5),
(920, 'Nihil Light', 'The user releases a light that nullifies all laws, hitting the target regardless of type or stat changes. This move can also hit Fairy-type Pokémon.', 200, 'special', 'Dragon', NULL, 0, 1);
